solution_code:
#include <stdio.h>
#include <stdlib.h>

int *safe_alloc(int n) {
    if (n <= 0) return NULL;
    return malloc((size_t)n * sizeof(int));
}

void safe_free(int **pptr) {
    if (!pptr || !*pptr) return;
    free(*pptr);
    *pptr = NULL;
}

int sum_and_free(int *arr, int n) {
    int sum = 0;
    for (int i = 0; i < n; i++)
        sum += arr[i];
    safe_free(&arr);
    return sum;
}

int main(void) {
    int *a = safe_alloc(3);
    if (!a) return 1;
    a[0] = 10; a[1] = 20; a[2] = 30;
    printf("%d\n", sum_and_free(a, 3));
    return 0;
}

validation.test_code:
void test_safe_alloc_valid(void) {
    int *p = safe_alloc(4);
    TEST_ASSERT_NOT_NULL(p);
    free(p);
}

void test_safe_alloc_invalid(void) {
    TEST_ASSERT_NULL(safe_alloc(0));
    TEST_ASSERT_NULL(safe_alloc(-1));
}

void test_safe_free_nullifies(void) {
    int *p = safe_alloc(2);
    TEST_ASSERT_NOT_NULL(p);
    safe_free(&p);
    TEST_ASSERT_NULL(p);
}

void test_safe_free_idempotent(void) {
    int *p = safe_alloc(1);
    TEST_ASSERT_NOT_NULL(p);
    safe_free(&p);
    /* deuxième appel ne doit pas planter */
    safe_free(&p);
    TEST_ASSERT_NULL(p);
}

void test_sum_and_free_result(void) {
    int *arr = safe_alloc(4);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 1; arr[1] = 2; arr[2] = 3; arr[3] = 4;
    int s = sum_and_free(arr, 4);
    TEST_ASSERT_EQUAL_INT(10, s);
}

int main(void) {
    RUN_TEST(test_safe_alloc_valid);
    RUN_TEST(test_safe_alloc_invalid);
    RUN_TEST(test_safe_free_nullifies);
    RUN_TEST(test_safe_free_idempotent);
    RUN_TEST(test_sum_and_free_result);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
